// ─── EXPORTAR CSV ────────────────────────────────────────────────────────────
function exportCSV() {
  const reviewDate = document.getElementById('review-date').value || new Date().toISOString().split('T')[0];
  const BOM = '﻿';
  const esc = s => '"' + String(s).replace(/"/g,'""') + '"';
  const statusText = f => { const s=dateStatus(f); if(s==='ok')return'Cerrada'; if(s==='vencida')return'Vencida'; if(s==='pendiente')return'Pendiente'; return'Sin fecha'; };
  const headers = ['Equipo','Clasificacion','ID Evento','Fecha Evento','Descripcion Evento','Accion','Responsable','Fecha Accion','Estado Fecha','Completada'];
  const rows = [];
  for (const ev of events) {
    for (const a of ev.actions) {
      rows.push([`ENG-${ev.equipo.replace('E','')}`,ev.clas,ev.id,ev.fecha,ev.desc,a.desc,a.resp,a.fecha||'Sin fecha',statusText(a.fecha),a.done?'SI':'NO']);
    }
  }
  const csv = BOM + [headers,...rows].map(r => r.map(esc).join(';')).join('\r\n');
  const blob = new Blob([csv], {type:'text/csv;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `ENG_Pulling_CGC_${reviewDate.replace(/-/g,'')}.csv`;
  a.click();
  URL.revokeObjectURL(url);
}

